B.a09=new A.af([B.m,"Treats the next played deck card as a Joker, allowing you to capture any unmatched card from the field.",B.n,"\u6b21\u306b\u51fa\u3059\u5c71\u672d\u306e\u30ab\u30fc\u30c9\u3092\u30b8\u30e7\u30fc\u30ab\u30fc\u3068\u3057\u3066\u6271\u3044\u3001\u5834\u306e\u597d\u304d\u306a\u30ab\u30fc\u30c9\u30921\u679a\u78ba\u5b9f\u306b\u7372\u5f97\u3057\u307e\u3059\u3002",B.o,"\u5c06\u4e0b\u4e00\u5f20\u6253\u51fa\u7684\u724c\u5e93\u724c\u89c6\u4e3a\u9b3c\u724c\uff0c\u8ba9\u4f60\u80fd\u593a\u53d6\u573a\u4e0a\u4e00\u5f20\u4efb\u610f\u5361\u724c\u3002",B.p,"\u5c07\u4e0b\u4e00\u5f35\u6253\u51fa\u7684\u724c\u5eab\u724c\u8996\u70ba\u9b3c\u724c\uff0c\u8b93\u4f60\u80fd\u596a\u53d6\u5834\u4e0a\u4e00\u5f35\u4efb\u610f\u5361\u724c\u3002"],t.C)
B.a0b=new A.af([B.m,"Forcefully steal one specific card from the opponent's captured area. (Once per game)",B.n,"\u76f8\u624b\u304c\u7372\u5f97\u3057\u305f\u30ab\u30fc\u30c9\u306e\u4e2d\u304b\u3089\u3001\u597d\u304d\u306a\u30ab\u30fc\u30c9\u30921\u679a\u5f37\u5236\u7684\u306b\u596a\u3044\u53d6\u308a\u307e\u3059\u3002(1\u30b2\u30fc\u30e01\u56de)",B.o,"\u5f3a\u5236\u4ece\u5bf9\u624b\u5f97\u5206\u533a\u593a\u53d6\u7279\u5b9a\u7684\u4e00\u5f20\u724c\u3002\uff08\u6bcf\u5c40\u9650\u4e00\u6b21\uff09",B.p,"\u5f37\u5236\u5f9e\u5c0d\u624b\u5f97\u5206\u5340\u596a\u53d6\u7279\u5b9a\u7684\u4e00\u5f35\u724c\u3002\uff08\u6bcf\u5c40\u9650\u4e00\u6b21\uff09"],t.C)
B.a0c=new A.af([B.m,"Collect all cards on the field, shuffle them back into the deck, and redeploy them.",B.n,"\u5834\u306b\u51fa\u3066\u3044\u308b\u30ab\u30fc\u30c9\u3092\u3059\u3079\u3066\u56de\u53ce\u3057\u3001\u5c71\u672d\u3068\u6df7\u305c\u3066\u518d\u914d\u7f6e\u3057\u307e\u3059\u3002",B.o,"\u5c06\u573a\u4e0a\u6240\u6709\u5361\u724c\u6536\u56de\uff0c\u4e0e\u724c\u5e93\u91cd\u65b0\u6d17\u724c\u5e76\u518d\u6b21\u5e03\u9635\u3002",B.p,"\u5c07\u5834\u4e0a\u6240\u6709\u5361\u724c\u6536\u56de\uff0c\u8207\u724c\u5eab\u91cd\u65b0\u6d17\u724c\u4e26\u518d\u6b21\u5e03\u9663\u3002"],t.C)
B.a03=new A.af([B.m,"Significantly increases the chance of Gwang (Bright) cards appearing in the initial deal.",B.n,"\u6700\u521d\u306e\u30ab\u30fc\u30c9\u914d\u5e03\u6642\u3001\u624b\u672d\u3084\u5834\u306b\u5149(\u5149\u672d)\u304c\u914d\u7f6e\u3055\u308c\u308b\u78ba\u7387\u304c\u5927\u5e45\u306b\u5897\u52a0\u3057\u307e\u3059\u3002",B.o,"\u5f00\u5c40\u53d1\u724c\u65f6\uff0c\u5927\u5e45\u589e\u52a0\u5149\u724c\u51fa\u73b0\u5728\u624b\u724c\u6216\u573a\u4e0a\u7684\u51e0\u7387\u3002",B.p,"\u958b\u5c40\u767c\u724c\u6642\uff0c\u5927\u5e45\u589e\u52a0\u5149\u724c\u51fa\u73fe\u5728\u624b\u724c\u6216\u5834\u4e0a\u7684\u6a5f\u7387\u3002"],t.C)
B.a05=new A.af([B.m,"Prevents Game Over once per round by covering the basic bet amount if you go bankrupt.",B.n,"\u8a72\u5f53\u30e9\u30a6\u30f3\u30c9\u3067\u7834\u7523(\u8cc7\u91d1\u4e0d\u8db3)\u3057\u305f\u969b\u30011\u56de\u3060\u3051\u57fa\u672c\u8ced\u3051\u91d1\u3092\u30ab\u30d0\u30fc\u3057\u3001\u30b2\u30fc\u30e0\u30aa\u30fc\u30d0\u30fc\u3092\u9632\u304e\u3057\u307e\u3059\u3002",B.o,"\u5728\u8be5\u56de\u5408\u7834\u4ea7\u65f6\uff0c\u4ec5\u9650\u4e00\u6b21\u4e3a\u4f60\u57ab\u4ed8\u57fa\u7840\u8d4c\u6ce8\uff0c\u9632\u6b62\u6e38\u620f\u7ed3\u675f\u3002",B.p,"\u5728\u8a72\u56de\u5408\u7834\u7834\u6642\uff0c\u50c5\u9650\u4e00\u6b21\u70ba\u4f60\u588a\u4ed8\u57fa\u790e\u8ced\u6ce8\uff0c\u9632\u6b62\u904a\u6232\u7d50\u675f\u3002"],t.C)
B.a0f=new A.af([B.m,"A high-risk, high-return item that multiplies your final score by 5 times if you win the round.",B.n,"\u30e9\u30a6\u30f3\u30c9\u52dd\u5229\u6642\u306b\u3001\u6700\u7d42\u30b9\u30b3\u30a2\u3092\u7121\u6761\u4ef6\u306b5\u500d\u306b\u3059\u308b\u30cf\u30a4\u30ea\u30b9\u30af\u30cf\u30a4\u30ea\u30bf\u30fc\u30f3\u30a2\u30a4\u30c6\u30e0\u3002",B.o,"\u9ad8\u98ce\u9669\u9ad8\u56de\u62a5\u7684\u6d88\u8017\u54c1\uff0c\u83b7\u80dc\u65f6\u76f4\u63a5\u5c06\u6700\u7ec8\u5f97\u5206\u4e58\u4ee55\u500d\u3002",B.p,"\u9ad8\u98a8\u96aa\u9ad8\u56de\u5831\u7684\u6d88\u8017\u54c1\uff0c\u7372\u52dd\u6642\u76f4\u63a5\u5c07\u6700\u7d42\u5f97\u5206\u4e58\u4ee55\u500d\u3002"],t.C)
B.a08=new A.af([B.m,"Adds an extra 0.5x to 2x multiplier when you declare 3 Go or more.",B.n,"\u30b2\u30fc\u30e0\u4e2d\u30013Go\u4ee5\u4e0a\u3092\u5ba3\u8a00\u3057\u305f\u5834\u5408\u3001\u6700\u7d42\u500d\u7387\u306b0.5\u500d\u301c2\u500d\u3092\u8ffd\u52a0\u3057\u307e\u3059\u3002",B.o,"\u5ba3\u544a 3 Go \u4ee5\u4e0a\u65f6\uff0c\u6700\u7ec8\u500d\u7387\u4f1a\u968f\u673a\u989d\u5916\u589e\u52a0 0.5 \u5230 2 \u500d\u3002",B.p,"\u5ba3\u544a 3 Go \u4ee5\u4e0a\u6642\uff0c\u6700\u7d42\u500d\u7387\u6703\u96a8\u6a5f\u984d\u5916\u589e\u52a0 0.5 \u5230 2 \u500d\u3002"],t.C)
B.a0g=new A.af([B.m,"Defends once against the opponent capturing your cards when you make a Ppeok (Bomb-fail).",B.n,"\u30d7\u30ec\u30a4\u30e4\u30fc\u304c\u30b7\u30e7\u30f3\u3092\u51fa\u3057\u305f\u6642\u3001\u76f8\u624b\u304c\u305d\u306e\u30ab\u30fc\u30c9\u3092\u98df\u3079\u308b\u306e\u3092\u6700\u521d\u306e1\u56de\u3060\u3051\u9632\u304e\u307e\u3059\u3002",B.o,"\u5f53\u4f60\u6253\u51fa\u7206\uff08Ppeok\uff09\u65f6\uff0c\u9996\u6b21\u9632\u5fa1\u5bf9\u624b\u5c06\u5176\u5403\u6389\u3002",B.p,"\u7576\u4f60\u6253\u51fa\u7206\uff08Ppeok\uff09\u6642\uff0c\u9996\u6b21\u9632\u79a6\u5c0d\u624b\u5c07\u5176\u5403\u6389\u3002"],t.C)
